sql:
SELECT first_name, last_name, position
FROM players
WHERE team_id = (
    SELECT team_id
    FROM team_statistics
    WHERE points = (
        SELECT MAX(points)
        FROM team_statistics
    )
);

external_knowledge:
- "Active players on the field" refers to teams that have played the most games;
- "Steering their ships" is a metaphor for the head coach;
- "From the most active to those who have just dipped their toes in the water" means sorting from the highest number of games played to the lowest.

- "light the victory flame" is a metaphor for winning games;
- "fiery battlefield" is a metaphor referring to the recent competitive games;
- "twice or more times in a row over the same adversary" implies at least two victories against the same opponent;
- "last ten days" refers to the time period of the games considered.

sql:
SELECT team_id, COUNT(*) AS total_games
FROM games
GROUP BY team_id;

SELECT team_id, MAX(points_for) AS peak_scoring_performance
FROM game_statistics
GROUP BY team_id;

external_knowledge:
- "squads" and "groups" refer to teams;
- "matches" refers to games;
- "most active players" refers to teams that have played the most games.

sql:
SELECT t.team_name
FROM teams t
JOIN team_statistics ts ON t.team_id = ts.team_id
WHERE ts.points = (
  SELECT MAX(points) FROM team_statistics
);

SELECT game_duration 
FROM games 
WHERE game_id = 1;

SELECT team_id, points_for
FROM game_statistics
WHERE points_for = (SELECT MAX(points_for) FROM game_statistics);

SELECT t.team_name, t.head_coach, ts.wins
FROM teams t
INNER JOIN team_statistics ts ON t.team_id = ts.team_id
WHERE ts.points = (
    SELECT MAX(points) FROM team_statistics
);
